"use client"; // Required for useState and useEffect in Next.js

import { useState, useEffect, } from "react";
import React from "react";
import ReactDOM from "react-dom";
import Countdown from "react-countdown";

export default function Home() {
  const adjectives = [
    "Hope",
    "Love",
    "Ambition",
    "Wit",
    "Bravery",
    "Fear",
    "Enthusiasm",
    "Strength",
    "Passion",
    "Trust",
  ];

  const [currentIndex, setCurrentIndex] = useState(0);
  const [isFinished, setIsFinished] = useState(false);

  useEffect(() => {
    const interval = setInterval(() => {
      setCurrentIndex((prevIndex) => (prevIndex + 1) % adjectives.length);
    }, 100);

    const timeout = setTimeout(() => {
      setIsFinished(true);
      clearInterval(interval);
    }, 5000);

    return () => {
      clearInterval(interval);
      clearTimeout(timeout);
    };
  }, [adjectives.length]);

  return (
    /* 
      FIX 1: Changed min-h-screen to h-screen to strictly lock down height to exactly 1 viewport window size.
      FIX 2: Added max-h-screen to hard-cap element layout.
    */
    <div className="flex items-center justify-center h-screen w-screen overflow-hidden max-h-screen relative">
      <main className="flex flex-col items-center justify-center font-black uppercase scale-y-150 text-center h-32 select-none">
        <h1 className="">You Can Have</h1>

        {!isFinished && (
          <h1 className="line-through">{adjectives[currentIndex]}</h1>
        )}

        {isFinished && <h1>Faith</h1>}
      </main>
    </div>
  );
}
